public boolean bobThere(String str)
{
    int firstBLocation = str.indexOf("b");
    int nextBLocation = str.indexOf("b", firstBLocation + 2);
    if (firstBLocation != nextBLocation && nextBLocation - firstBLocation == 2)
    {
        return true;
    }
    else
    {
        return false;
    }
}

